    // .............
    // #2: ATimeofWarIntro

    void passage2_Init()
    {
        this.Passages[@"ATimeofWarIntro"] = new StoryPassage(@"ATimeofWarIntro", new string[] { "INTRO", "rev2", }, passage2_Main);
    }

    IStoryThread passage2_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION I : Choisir son camp");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Mon père était un génie ! Je l'affirme maintenant, non pas avec la naïveté de la découverte initiale de son journal, mais comme une vérité établie éprouvée par le temps. C'est pourquoi aujourd'hui je rédige ces mots pour la postérité et pour clamer avec la plus grande conviction le fondement de ce que certains peuvent qualifier à tort de science folle.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Lors de ma première visite du manoir de mon père, j'étais aussi sceptique que n'importe quel autre individu normalement constitué. Las de mon excursion à travers les plaines hongroises, les murs froids et gris de la villa aux portes en fer oppressantes m'ont glacé le sang. Quand l'assistant défiguré, la seule personne dans le secret des dieux, m'a dévoilé une porte dérobée et un escalier en colimaçon menant à un laboratoire secret souterrain, cette sinistre découverte n'a rien fait pour apaiser mes nerfs. En fait, la vision de bocaux renfermant de la chair préservée et l'odeur astringente des produits chimiques n'ont fait qu'aggraver mon état de fragilité et j'ai dû souper dans ma chambre pendant plusieurs semaines.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Mais c'est cette même sinistre découverte qui m'a finalement permis de me remettre de mon affliction. En effet, alors que je parcourais page après page le journal qui m'avait été légué et que je découvrais les formules des expériences qui y étaient consignées, mes appréhensions se sont peu à peu évanouies. Malgré une certaine nervosité, j'étais véritablement enthousiaste devant les implications éthiques de cette grande tâche !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Pourtant, même après que mon âme troublée a été apaisée, la cacophonie des festivités de la ville voisinouie faisaient trembler les vitres de mes fenêtres. Dans un premier temps, je me limitais à des visites brèves et peu fréquentes du bourg. À chaque fois que je tournais la tête, j'avais l'impression de croiser des yeux inquisiteurs et je sentais sur ma nuque les picotements de petites dagues comme si cette ville m'épiait de son regard d'acier. Je ne pouvais que supposer que les autres membres de ma famille subissaient le même traitement sordide.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"C'est la personne qui partage ma vie, profitant de mon repos prolongé pour faire connaissance avec les habitants, qui m'a expliqué que cette agitation était provoquée par des débats politiques enflammés. J'ai alors pu discerner le cri de ralliement de leurs manifestations nocturnes au cours desquelles ils parlaient de désobéissance, de la fin de la monarchie et de guerre civile.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"J'ai commencé à réaliser le potentiel bénéfice de la guerre pour mes recherches. Si les gens partageaient ne serait-ce qu'une fraction de la passion qui alimente désormais le feu de mon cœur, ils accepteraient facilement mon assistance scientifique ! Alors que mon père ne manquait pas d'ambition, c'est son existence de reclus qui a condamné ses idées à l'obscurité.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Je ne referai pas la même erreur. Je braverai les quolibets de la populace pour apprendre à ces gens l'art de la guerre. Mes efforts seront déterminant pour le cours de ce conflit. Et quand le moment sera venu, c'est ma science qui émergera triomphante des flammes de la guerre !");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "IntroConflict", null);
        yield return lineBreak();
        Vars.rumblings = 0;
        Vars.war = macros1.either(1, 2);
        Vars.warwinner = macros1.either("Séparatistes", "Monarchistes Unifiés");
        if (Vars.warwinner == "Séparatistes")
        {
            Vars.crest = "Faucille";
            Vars.warloser = "Monarchistes Unifiés";
            Vars.figure = "Bouclier";
        }
        if (Vars.warwinner == "Monarchistes Unifiés")
        {
            Vars.crest = "Bouclier";
            Vars.warloser = "Séparatistes";
            Vars.figure = "Faucille";
        }
        if (Vars.warwinner == "Séparatistes")
        {
            Vars.quarter = macros1.either("oui", "non");
        }
        Vars.crazy = 0;
        Vars.barracksact = macros1.either("hostile", "amical");
        Vars.sep = 0;
        Vars.mon = 0;
        Vars.gunsbonus = 0;
        yield break;
    }


