    IStoryThread passage6_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Visite à l\'Hôtel de ville");
        }
        yield return lineBreak();
        yield return text("J\'ai décidé d\'assister à l\'une des réunions du conseil municipal à l\'Hôtel de vil" +
            "le. ");
        yield return text(macros1.either("Dans une aussi petite ville rurale, l\'ambiance était toujours animée avec au moin" +
            "s une dispute éclatant après les propos insultant d\'un des habitants. Cette atmo" +
            "sphère animée m\'intriguait et je décidai d\'en savoir plus.", @"Bien que les curiosités - et les odeurs - de cet établissement civique étaient de nature à procurer une certaine distraction, je ne pouvais pas me permettre de me laisser distraire. J'étais ici pour en savoir plus au sujet des factions politiques puisque j'avais parfaitement conscience que je pouvais tirer profit de ces informations.", @"Mes visites en ce lieu ne m'apportaient jamais vraiment satisfaction. Cependant, il était de mon devoir de faire acte de présence et la personne qui partageait ma vie insistait pour que je me mêle à la population. Aussi, il m'a fallu prendre sur moi pour m'accommoder à cette situation de tension avant d'aller parler à la première personne vaguement intéressante.", @"Ces événements tempétueux - sans doute plus intéressants à observer qu'à vivre - se déroulaient au coucher du soleil et se prolongeaient tard dans la soirée. Au fur et à mesure que la nuit avançait et que, inévitablement, les esprits s'échauffaient sous les effets des alcools d'une distillerie locale, je me sentais de plus en plus à mon aise dans cet environnement. Au cours de cette réunion particulière, quelques personnes avaient suscité ma curiosité."));
        yield return lineBreak();
        Vars.rumblings = int.Parse(Vars.rumblings) + 1;
        yield return lineBreak();
