    IStoryThread passage8_Fragment_9()
    {
        yield return text("L\'officier a d\'abord hésité à me révéler la moindre information intéressante, mai" +
            "s ma position neutre l\'a intrigué. Lorsque j\'ai évoqué la possibilité d\'un inves" +
            "tissement significatif en ville, ");
        if (Vars.war == 1)
        {
            yield return text(@"il s'est tendu. J'ai remarqué son appréhension. ""J'y réfléchirais à deux fois,"" a-t-il dit. Puis, avec une main en coupe contre sa joue, il a murmuré, ""Cette ville occupe une position militaire stratégique dans ce pays. Si j'étais vous, je partirais d'ici. Sauf, bien entendu, si vous appréciez de vivre dans une ville dévastée transformée en champ de bataille.""");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Il m\'a alors confié une petite statuette en métal en forme de ");
            yield return text(Vars.crest);
            yield return text(". Je ne comprenais pas l\'importance de ce geste, mais je me doutais que cela me s" +
            "erait révélé plus tard.");
            yield return lineBreak();
            yield return lineBreak();
            if (Vars.crest == "Faucille")
            {
                //yield return enchantIntoLink("Cliquez pour continuer...", passage8_Fragment_1);
                using (styleScope("hook", "h00000801"))
                    yield return link("Cliquez pour continuer...", null, () => enchantHook("h00000801", HarloweEnchantCommand.Replace, passage8_Fragment_0));

            }
            else if (Vars.crest == "Bouclier")
            {
                //yield return enchantIntoLink("Cliquez pour continuer...", passage8_Fragment_3);
                using (styleScope("hook", "h00000803"))
                    yield return link("Cliquez pour continuer...", null, () => enchantHook("h00000803", HarloweEnchantCommand.Replace, passage8_Fragment_2));

            }
        }
        if (Vars.war == 2)
        {
            yield return text("il a souri et a posé un doigt sur ses lèvres. ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("\"Je pense que vos craintes ne sont pas justifiées. Les ");
            yield return text(Vars.warwinner);
            yield return text("envisagent de construire une caserne dans les années à venir. Cela signifie la st" +
            "abilité, la prospérité et des ");
            using (styleScope("italic", true))
            {
                yield return text("opportunités.");
            }
            yield return text("\"");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Puis l\'officier m\'a cordialement serré la main. Quand il me l\'a lâchée, j\'avais d" +
            "ans la paume une petite statuette argentée en forme de ");
            yield return text(Vars.crest);
            yield return text(". \"Voici pour votre ");
            using (styleScope("italic", true))
            {
                yield return text("soutien");
