    IStoryThread passage13_Fragment_4()
    {
        if (Vars.war == 1)
        {
            yield return text("Alors que je m\'approchais, l\'individu à la dent cassée renifla bruyamment - de l\'" +
            "autre bout de la pièce, on pouvait sentir le fumet qu\'il dégageait. Puis il y eu" +
            "t un long silence gêné durant lequel il me regarda droit dans les yeux.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Soudain, il prit quelque chose dans sa poche déchirée et en sortit une petite statuette en bois difforme. Il s'approcha et, avec une haleine de poisson fermenté, me murmura à l'oreille. ""Nous ne risquons rien. John veillera à votre sécurité. La guerre ne nous touchera jamais. Je le promets, Capitaine.""");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Quand vous avez fini de lire, cliquez ici pour continuer...", passage13_Fragment_1);
            using (styleScope("hook", "h0001301"))
                yield return link("Quand vous avez fini de lire, cliquez ici pour continuer...", null, () => enchantHook("h0001301", HarloweEnchantCommand.Replace, passage13_Fragment_0));

        }
        //if (Vars.war == 2)
        else
        {
            yield return text(@"Tandis que j'approchais, l'individu à la dent cassée m'a fait signe de venir plus près. Alors que j'étais à quelques pas, il s'est précipité vers moi et s'est agenouillé avant de prendre mes deux mains dans les siennes. Sa puanteur indicible me fit monter les larmes aux yeux.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("\"Repentez-vous,\" dit-il. \"La fin est proche. La bataille est perdue. Perdue. Perd" +
            "ue. Perdue.\" Il frissonna et de sa barbe mal entretenue tomba un peu de poussièr" +
            "e blanche.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"J'avais l'impression d'avoir commis une erreur en ayant voulu parler à cette âme misérable et j'en ai profité pour m'éloigner rapidement. Un peu plus tard, avec contrariété, j'ai découvert que l'individu avait habilement glissé une statuette en bois difforme dans mon sac à bandouilère.");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Quand vous avez fini de lire, cliquez ici pour continuer...", passage13_Fragment_3);
            using (styleScope("hook", "h00001303"))
                yield return link("Quand vous avez fini de lire, cliquez ici pour continuer...", null, () => enchantHook("h00001303", HarloweEnchantCommand.Replace, passage13_Fragment_2));

        }
        //yield return link("Quand vous avez fini de lire, cliquez ici pour continuer...", "RumorCreep", null);
        yield break;
    }

