            "Remettez dans la boîte du scénario tous les jetons <sprite=\"S3_SickleToken\" index=0> <sprite=\"S3_ShieldToken\" index=0> " +
            "et les jetons <sprite=\"S3_WoodenFigureToken\" index=0> non utilisés.";
        ViewEndOfGeneration.S_OnEndOfGeneration?.Invoke(s, 3);
        using (styleScope("bold", true))
        {
            yield return text("Une ville fortifiée");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Les ");
        yield return text(Vars.warwinner);
        yield return text(" ");
        yield return text("ont repoussé le front loin de notre belle ville et ont pris le contrôle du gouver" +
            "nement local. ");
        if (Vars.barracks == "non")
        {
            yield return text("Contre ma volonté, la Caserne a été construite par les ");
            yield return text(Vars.warwinner);
            yield return text(", renforçant ainsi leur position dans la région. Il semble que ma progéniture dev" +
            "ra se montrer plus ferme pour peser sur l\'orientation de ce conflit.");
        }
        if (Vars.barracks == "oui")
        {
            yield return text("Selon mes instructions, la ");
            using (styleScope("bold", true))
            {
                yield return text("Caserne");
            }
            yield return text("a été construite par les ");
            yield return text(Vars.warwinner);
            yield return text(", renforçant ainsi leur position dans la région. Bien que je ne verrai pas la fin" +
            " de ce conflit de mon vivant, grâce à mes efforts, cet honorable et décisif héri" +
            "tage perdurera.");
        }
        yield return text(" ");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Il n'y a rien d'étonnant à ce que mon arrivée dans ce monde froid se soit faite en maugréant, en luttant chaque jour contre l'ignorance des hommes, et, aujourd'hui, je m'apprête à tirer ma révérence en pleine tourmente. Car c'est en se battant et en étant doté d'une ambition ne souffrant aucun remords que l'on peut laisser son empreinte dans les annales de l'histoire !");
