    IStoryThread passage31_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Une découverte opportune");
        }
        yield return lineBreak();
        yield return text(@"Si vous ne prêtez pas foi à la suite de mon récit, c'est que vous êtes certainement une personne saine d'esprit. Je ne divulguerai pas les détails spécifiques concernant ce lieu, mais l'énigmatique carte nous mena à une mine d'argent abandonnée près des ruines de la ville. Brandissant haut nos lanternes, nous nous aventurâmes dans les galeries enténébrées en suivant les courbes du réseau de rails jusqu'à une alcôve où des pancartes d'avertissement avaient été installées par les ouvriers plusieurs années auparavant.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Alors que nous nous approchions, une grande structure métallique se mit à bourdonner. Des étincelles bleues couraient sur sa surface et éclairaient la grotte. Dans un flash soudain, une porte s'ouvrit dans la structure et une brume épaisse se déversa le long des rails. ");
        yield return text(Vars.playtxt);
        yield return text(" ");
        yield return text("sièges en cuir étaient disposés le long des parois intérieures de la machine.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Sans la moindre hésitation, nous franchîmes l'entrée avant de nous installer sur les fauteuils. Alors que nous nous attachions avec les sangles, nous entendîmes un sifflement bruyant comme si de la vapeur fusait par quelques conduits invisibles. Puis la porte se referma. Les parois métalliques vibrèrent violemment, nous secouant dans nos fauteuils.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Des cadrans se mirent à tourner avant d\'afficher le chiffre ");
        using (styleScope("bold", true))
        {
            yield return text("1831");
        }
        yield return text(" ");
        yield return text("tandis que la réalité se pliait autour de nous et nous enveloppait comme un ridea" +
            "u de soie.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour voyager à travers le temps et l\'espace...", "TimeMachineExperiment", null);
        yield return lineBreak();
        yield break;
    }


