    IStoryThread passage41_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION III : Lourde est la couronne");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Il y a deux manières d'acquérir de l'influence : grâce à l'argent (ce qui est aussi séduisant que sournois) et grâce au sang versé. Bien que je n'aie pas passé de nombreuses années dans ce monde infâme, j'ai tout de même appris cette précieuse vérité en ce court laps de temps.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les griefs féroces des habitants de la ville étaient devenus si fréquents que de les voir se contenter de murmures méprisants était une nette amélioration qui rendait mes excursions en ville infiniment plus supportables. Avec le temps, le mouvement Séparatiste s'était éteint, ce qui avait permis de mettre un terme à cette entreprise guerrière exaspérante (bien que lucrative) et la paysannerie avait repris son habitude d'exprimer un vain mécontentement.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"À cette époque, l'influence de notre famille nous avait permis d'avoir l'oreille du trône. Grâce à des placements judicieux, il nous a été accordé un poste au conseil permettant d'influer sur les positions officielles et de traiter des questions régionales. Il nous fallait maintenir un équilibre délicat : tant que nos travaux demeuraient discrets, nous pouvions conserver notre influence et éviter toutes fâcheuses conséquences. Cependant, si nous attirions l'attention, nous ne pourrions plus jouir de cette paix. Inquiète est la tête qui porte une couronne, comme disait le Barde.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Cette proposition me ravissait et j'ai demandé à mes serviteurs de donner le meilleur d'eux-mêmes pour accueillir de potentiels visiteurs ; car, même si l'idée de m'occuper des affaires administratives de la couronne me plongeait dans un état de léthargie avancé, je me rendais bien compte du pouvoir qu'il était possible d'exercer en contrôlant subtilement les dirigeants. Et que je doive les couvrir d'or ou regarder couler des rivières de sang, un tel pouvoir me serait octroyé !");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "RoyalBarnCheck", null);
        yield return lineBreak();
        if (Vars.townname == "Debug")
        {
            yield return text("v1.1");
        }
        if (Vars.MonarchReignIntro == 0 || Vars.MonarchReignIntro == "")
        {
            Vars.tracker = int.Parse(Vars.tracker) - 1;
            if (Vars.players == 5)
            {
                Vars.tracker = int.Parse(Vars.tracker) - 1;
            }
        }
        Vars.decbon = macros1.either(5, 6, 7, 8);
        if (Vars.warloser == "Monarchistes Unifiés")
        {
            Vars.endchange = "oui";
        }
        if (Vars.players == 2)
        {
            Vars.commtrigger = macros1.either(2, 3, 4);
        }
        if (Vars.players == 3)
        {
            Vars.commtrigger = macros1.either(3, 4, 5);
        }
        if (Vars.players == 4)
        {
            Vars.commtrigger = macros1.either(4, 5, 6);
        }
        if (Vars.players == 5)
        {
            Vars.commtrigger = macros1.either(5, 6, 7);
        }
