    // .............
    // #42: PeaceIntro

    void passage42_Init()
    {
        this.Passages[@"PeaceIntro"] = new StoryPassage(@"PeaceIntro", new string[] { "INTRO", "revised", }, passage42_Main);
    }

    IStoryThread passage42_Main()
    {
        yield return text("GÉNÉRATION III - La paix par la guerre");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les festivités ont commencé juste à mon arrivée. Les structures gothiques habituellement austères étaient décorées de rubans aux couleurs vives, de ballons et de pots débordant de bortsch. En uniforme, les soldats conquérants défilaient en formation impeccable dans les rues pavées pour célébrer la victoire des Séparatistes. Il y avait un tel contraste entre les miliciens négligés de ma jeunesse et les démocrates révolutionnaires acclamant la nation hongroise à chaque coup de botte d'un soldat.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Cependant, ce n'est pas ce spectacle ennuyeux qui a éveillé en moi une passion infernale, mais bien l'ardeur de la population. Enhardie par ce triomphe contre un pouvoir monarchique et vivifiée par une immense fierté pour cette nation, cette juste ferveur s'est muée en frénésie. En quelques semaines, un parti nationaliste extrêmiste a pris le pouvoir et ce bref répit après la guerre a cédé la place à de grandes ambitions.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Le gouvernement avait compris que le seul moyen d'assurer une paix durable dans le pays et dans les territoires environnants instables était de contraindre la coopération par une utilisation judicieuse de la force militaire. La réputation de ma famille au sein de la communauté scientifique me valait de faire autorité en matière d'armes expérimentales. Dans cette optique visant à contrôler le monde, je savourais la possibilité qui m'était offerte d'observer les effets dévastateurs de ces merveilleuses machines.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Face à mon arsenal technologique, aucune nation ne pouvait espérer résister à notre puissance ! Notre armée allait assurer une paix durable qui inscrirait à tout jamais l'héritage de ma famille dans les annales de l'histoire humaine. Il n'y avait pas de temps à perdre ! Le moment était venu d'utiliser la science pour changer le monde !");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "SeparatistBarnCheck", null);
        yield return lineBreak();
        if (Vars.townname == "Debug")
        {
            yield return text("v1.1");
        }
        Vars.wlimit = macros1.either(4, 5);
        if (Vars.warloser == "Séparatistes")
        {
            Vars.endchange = "oui";
        }
        Vars.pea1 = 0;
        Vars.pea2 = 0;
        Vars.pea3 = 0;
        yield break;
    }


