    // .............
    // #50: WarningIntro

    void passage50_Init()
    {
        this.Passages[@"WarningIntro"] = new StoryPassage(@"WarningIntro", new string[] { "INTRO", "revised", }, passage50_Main);
    }

    IStoryThread passage50_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GÉNÉRATION III :  Conséquences futures");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Un avenir moderne");
        }
        yield return lineBreak();
        yield return text(@"Tandis que la découverte des carnets et des expériences des membres de ma famille allait servir de base à mes ambitions pour les années à venir, je ne les avais jamais rencontrés. J'étais trop jeune pour me rappeler la disparition de mon brillant ancêtre. Perdre un parent puis un second à cause de la démence que cela a provoquée était une folie à laquelle aucun enfant ne devrait être soumis. En séjournant à Vienne et en me consacrant à mes études jusqu'à ma vingt-et-unième année, cette réalité m’avait été épargnée. Ce n'est que parce que la personne partageant ma vie avait insisté que j'avais entrepris de régler le problème de mon héritage.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Je me souviens de ma stupéfaction en arrivant par le train un soir d'été. Malgré les anecdotes de ma nourrice, je ne savais pas à quoi m'attendre mais certainement pas à l'environnement urbain débordant d'activité que je découvris. Alors que le soleil disparaissait derrière la cime des arbres, la lumière des lampadaires modernes en acier accentuait la luminosité urbaine. Nous avons profité d'une balade en couple dans notre voiture à vapeur, ce qui nous a permis de découvrir cette communauté idyllique et sa population bien agréable appréciant la commodité des technologies de l'électricité et des turbines à vapeur.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Le domaine ne semblait pas avoir souffert des années d'inoccupation. Du lierre et des ronces récemment taillés ornaient le portail de fer et le parc était parfaitement entretenu. Nous avons été accueillis par un gardien fort âgé et par la petite équipe constituant le personnel de maison. Bien que moderniser le domaine aux standards de la ville proche allait demander beaucoup de travail, le chaleureux accueil des serviteurs avait apaisé nos dernières inquiétudes. En découvrant, le laboratoire de ma famille, ce qui ne devait être qu'une simple visite se mua en un séjour d'une durée indéfinie.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Cependant, quand j'évoquais l'histoire de ma famille en matière d'expérimentations, je suscitais rarement l'indifférence, mais plutôt de fermes encouragements. Il semblait que les habitants de cette région regorgeant de progrès inhabituels considéraient mes théories comme rudimentaires, mais aussi particulièrement avant-gardistes. Même quand je faisais allusion à de sombres rituels et à des expériences choquantes, ils m'encourageaient à approfondir ces sujets et à me rendre à l'université nouvellement construite.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Cela provoquait en moi une certaine consternation. N'était-ce pas ce que je voulais ? Un soutien sans faille des idées phares de ma famille et une voie dégagée vers l'illumination scientifique. Pourquoi considérais-je vexant le fait qu'ils ne se s'opposent pas à moi ? Considéraient-ils mes illustres travaux comme triviaux ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"C'est ce triste constat qui a renforcé ma détermination. Si ces modernistes timorés en voulaient encore plus, qu'il en soit ainsi ! Je repousserais les limites de la science bien plus loin qu'elles ne l'avaient jamais été, qu'elles qu'en soient les conséquences!");
        yield return lineBreak();
        yield return lineBreak();
        Vars.total = macros1.either(6, 7, 8, 9, 10);
        if (Vars.players == 4)
        {
            Vars.total = int.Parse(Vars.total) - 1;
        }
        if (Vars.players == 3)
        {
            Vars.total = int.Parse(Vars.total) - 2;
        }
        if (Vars.players == 2)
        {
            Vars.total = int.Parse(Vars.total) - 3;
        }
        Vars.search = 0;
        Vars.stasis = "non";
        Vars.ending = "ATOW-End4";
        Vars.master = 0;
        if (Vars.crazy >= 1)
        {
            using (styleScope("hook", "h00015"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h00015", HarloweEnchantCommand.Replace, passage50_Fragment_0));
        }
        else
        {
            yield return link("Cliquez pour continuer...", "Late2ResB", null);
        }
        yield return lineBreak();
        if (Vars.townname == "Debug")
        {
            yield return text("v1.1");
        }
        yield break;
    }

