    void passage53_Init()
    {
        this.Passages[@"WarningEvent"] = new StoryPassage(@"WarningEvent", new string[] { "INTRO", }, passage53_Main);
    }

    IStoryThread passage53_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Apparition des voyageurs temporels");
        }
        yield return lineBreak();
        yield return text("En un bref instant, la trajectoire de l\'univers avait changé. Je ne sais pas si q" +
            "uelqu\'un lira un jour ces quelques mots car même en ce moment-même ils apparaiss" +
            "ent et disparaissent sur la page.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Alors que nous profitions avec les membres de ma famille d'une amicale conversation, nos tasses de thé se sont mises à vibrer sous l'effet d'une force inconnue. Dans un éclair aveuglant, une curieuse structure métallique ressemblant à une grande boîte est apparue devant nous en produisant un véritable nuage de poussière constellé d'étincelles et de brandons incandescents.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Soudain, la porte s'est ouverte à la volée et la silhouette d'une bête reptilienne aux yeux d'une blancheur éclatante a traversé la brume. Elle est tombée sur le tapis roussi, aussi mort que l'on peut l'être, son cou tranché et pourtant cautérisé, bien qu'un nouveau flot de sang noir ait coulé par terre. Se pourrait-il qu'il s'agisse... d'un dinosaure ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Une femme aux cheveux blancs a émergé de la brume chimique en se tenant les côtes. La vieille dame était vêtue d'une tenue métallique qui était à la fois exotique et intrigante. Le matériau brillant était entaillé comme si des griffes incroyablement grandes l'avaient déchiré et sa combinaison était souillée d'une substance liquide (principalement du sang noir). Derrière elle, parmi des fauteuils dotés de sangles, il y avait ");
        if (Vars.players == 2)
        {
            yield return text("un autre scientifique");
        }
        if (Vars.players == 3)
        {
            yield return text("deux autres scientifiques");
        }
        if (Vars.players == 4)
        {
            yield return text("trois autres scientifiques");
        }
        if (Vars.players == 5)
        {
            yield return text("quatre autres scientifiques");
        }
        yield return text(" ");
        yield return text("assis.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Elle se mit à parler d'une voix nerveuse : « Grâce à Dieu j'ai fini par vous trouver ! Vous devez refermer la boucle temporelle. Oh ! Comme nous nous sommes montrés présomptueux ! Croire que nous pourrions manipuler les forces de la quatrième dimension ! Notre erreur de calcul va maintenant provoquer notre perte. Bientôt, le temps tel que nous le connaissons aura cessé d'exister. » Elle nous fit un signe, mais ses traits émaciés ont pali quand une lueur cramoisie a soudain envahi la pièce.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("« J\'arrive trop tard ! Cela a déjà commencé ! » a-t-elle crié avant que la réalit" +
            "é ne se reforme autour d\'elle.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "TimeWarp1st", null);
        yield return lineBreak();
        yield break;
    }


