    void passage70_Init()
    {
        this.Passages[@"MartialSepEvent"] = new StoryPassage(@"MartialSepEvent", new string[] { }, passage70_Main);
    }

    IStoryThread passage70_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Escalade");
        }
        yield return lineBreak();
        yield return text("Tandis que la guerre se poursuivait sans relâche, c\'est moi qui en souffrais le p" +
            "lus. Les fortifications nécessitant un approvisionnement constant, il était de p" +
            "lus en plus difficile de me procurer les ingrédients nécessaires à mes expérienc" +
            "es.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Cependant, dans mon humble génie, j\'ai imaginé une solution en me basant sur une " +
            "seule question : pourquoi aurais-je besoin d\'ingrédients spéciaux alors que je p" +
            "ouvais installer des armes partout ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Bien entendu, cette méthode bâclée n'était ni idéale, ni digne, mais elle permettait d'obtenir un résultat dévastateur. Ma première démonstration pratique a poussé les deux camps à cesser les hostilités quand ils ont vu un petit bataillon réduit à l'état de tâches de vin sur le champ de bataille.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Cependant, les factions militaires de la région avaient encore besoin d'être convaincues puisque l'utilisation de nos armes était encore considérée comme un ""crime de guerre"". Il fallait donc faire preuve de persuasion pour employer ces nouvelles méthodes. Imaginez un peu ! La ""science"" considérée comme un crime de guerre ! N'est-ce pas le souhait le plus ardent d'un général d'obtenir la victoire la plus efficace possible ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez ici pour continuer...", "MartialSepEventa", null);
        yield return lineBreak();
        yield break;
    }


