        {
            using (styleScope("italic", true))
            {
                yield return text("TOUS les jetons révélés sont remis dans la réserve quel que soit le résultat.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("On répète ce processus en déplaçant le cube Occultisme sur la case suivante jusqu" +
            "\'à ce que toutes les batailles soient résolues.");
