    IStoryThread passage74_Main()
    {
        if (Vars.timemistake < 8)
        {
            using (styleScope("bold", true))
            {
                yield return text("Monument au Progrès");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text("La ville a offert un témoignage de sa reconnaissance pour avoir incité sa populat" +
            "ion à emprunter une trajectoire vers un avenir utopique.");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage74_Fragment_1);
            using (styleScope("hook", "h00007401"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h00007401", HarloweEnchantCommand.Replace, passage74_Fragment_0));

        }
        if (Vars.timemistake == 8)
        {
            using (styleScope("bold", true))
            {
                yield return text("Reconstruire");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Sans qu\'aucun monument ne soit érigé, les derniers habitants de la région se sont" +
            " attelés à la tâche fastidieuse de la reconstruction dans un environnement ravag" +
            "é et déchiré par les paradoxes temporels et les entités interdimensionnelles.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Il m'a été difficile de l'accepter. J'avais tant fait, tant donné de moi-même. Ne recevoir aucune récompense pour avoir offert au monde le don du voyage dans le temps, malgré le chaos absolu que cela avait généré, a entaché ma réputation jusqu'alors irréprochable.");
        }
        yield return lineBreak();
        yield return lineBreak();
        //yield return link("Cliquez pour continuer...", "Scoring", null);
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.release >= 1)
        {
            Vars.giants = int.Parse(Vars.giants) - 1;
        }
        if (Vars.players == 2)
        {
            if (Vars.giants >= 1)
            {
                Vars.ending = "ATOW-End1";
            }
            else
            {
                Vars.ending = "ATOW-End2";
            }
        }
        if (Vars.players == 3)
        {
            if (Vars.giants >= 2)
            {
                Vars.ending = "ATOW-End1";
            }
            else
            {
                Vars.ending = "ATOW-End2";
            }
        }
        if (Vars.players == 4)
        {
            if (Vars.giants >= 3)
            {
                Vars.ending = "ATOW-End1";
            }
            else
            {
                Vars.ending = "ATOW-End2";
            }
        }
        if (Vars.players == 5)
        {
            if (Vars.giants >= 3)
            {
                Vars.ending = "ATOW-End1";
            }
            else
            {
                Vars.ending = "ATOW-End2";
            }
        }
        yield return lineBreak();
        yield break;
    }

