        }
        yield return lineBreak();
        yield return text(@"Malgré notre technologie d'armement supérieure et une réinterprétation avant-gardiste de l'éthique des conflits, certains pays voisins refusaient encore de se soumettre. Les généraux avaient préparé une ultime offensive qui allait déterminer l'issue de la guerre et si ce glorieux empire allait régner sur la création.");
