    IStoryThread passage92_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Retour vers le passé");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Aussi rapidement que cela avait commencé, le silence est retombé dans la singuliè" +
            "re pièce. La porte de la chambre s\'est décrochée de ses gongs pour tomber à plat" +
            " par terre dans un tourbillon d\'étincelles et de fumée.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Nous avons quitté la mine avant de nous diriger en toute hâte vers la ville. Les changements nous sautèrent immédiatement aux yeux : la ville avait retrouvé son aspect d'origine et se dressait telle qu'elle était en 1831. Nous savions que le destin, ou un quelconque bienfaiteur inconnu, nous avait donné la possibilité de corriger les erreurs du passé pour créer un meilleur avenir.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Me précipitant vers mon domaine j'y ai retrouvé une vision familière de ma jeunesse ; le portail gothique en pierre et en fer était aussi impressionnant que dans mon souvenir. Usant d'une imposture bien improvisée, j'ai indiqué à mes jeunes parents que j'étais un membre de la famille en vacances. Après une rapide intégration, j'ai pu reprendre mes expériences visant à trouver un moyen de retourner à mon époque tout en m'assurant que l'Histoire ne se répéterait pas.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le temps, semblait-il, n\'était pas de mon côté.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "TimeTokens", null);
        yield return lineBreak();
        yield break;
    }


