        using (styleScope("bold", true))
        {
            yield return text("Paradoxe évité");
        }
        yield return lineBreak();
        yield return text("Son audace et sa familiarité m\'intriguaient, aussi je l\'ai suivi jusqu\'à chez lui" +
            ", quelques pâtés de maison plus loin. Dès que nous sommes arrivés, il a ouvert l" +
            "a porte et a désigné du doigt une statuette de ");
        yield return text(Vars.crest);
        yield return text(". J\'ai alors sorti de ma poche la même statuette.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Bien que je me targue d'avoir d'excellents réflexes, la surprise a été totale quand l'homme, après avoir vu la statuette, fit preuve d'une fougue et d'une célérité incroyables pour me l'arracher des mains. Comme s'il était l'esclave d'une force inconnue, il a rapproché la ");
        yield return text(Vars.crest);
        yield return text(" ");
        yield return text("de la seconde statuette identique. J\'ai alors vu sa main gantée passer à travers " +
            "comme si elle n\'était qu\'une manifestation spectrale. Soudain, les deux statuett" +
            "es identiques se sont fondues l\'une à l\'autre en une seule pièce.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"L'homme a voulu retirer sa main alors que tout son corps tremblait et oscillait avec une saisissante intensité. Je pouvais sentir une onde de chaleur émanant de cet individu effrayé et j'ai à peine eu le temps de me protéger les yeux avant que la peau de son visage ne se mette à fondre comme la cire d'une bougie. Quelques secondes plus tard, sa tête a explosé projetant avec force ce qu'elle renfermait sur tous les murs de la pièce.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Il est certain qu\'en ce jour avait été mené une grande expérience sur les paradox" +
            "es temporels -  bien que je ne sache pas exactement à quoi elle ait pu servir.");
        yield return lineBreak();
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage109_Fragment_1);
        using (styleScope("hook", "h000010901"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000010901", HarloweEnchantCommand.Replace, passage109_Fragment_0));

        yield return lineBreak();
        yield break;
