            {
                yield return text("La Formation");
            }
            yield return lineBreak();
            yield return text(@"Lors d'un après-midi solitaire dans mon bureau, mon attention a été attirée par un curieux objet posé sur le manteau de ma cheminée : une statuette en bois taillée par un gentilhomme sans doute dérangé. Cependant, tandis que mon regard s'attardait sur ses contours, j'ai remarqué une curieuse entaille comme un raccord usé. J'ai contacté les autres membres de ma famille pour savoir si l'un d'eux avait acquis un objet similaire.");
            yield return lineBreak();
            yield return lineBreak();
            if (Vars.crazy > 1)
            {
                yield return text(@"Lors d'un souper convivial, nous avons découvert que les objets s'assemblaient pour former un motif très particulier. Avec un cliquetis métallique, les différentes pièces se sont soudain réarrangées pour prendre la forme brisée d'un homme en bois. Ses ligaments se sont rapidement contractés et, telle une araignée, la créature a détalé sur les murs avant de se mettre en position défensive sur la rampe d'escalier.");
                yield return lineBreak();
                yield return lineBreak();
                yield return text("Cela nous a beaucoup impressionné et, en ne déplorant qu\'un serviteur horriblemen" +
            "t mutilé pour y parvenir, nous avons capturé la bête afin de la mettre à profit " +
            "pour l\'effort de guerre.");
                yield return lineBreak();
                yield return lineBreak();
                //yield return enchantIntoLink("Cliquez pour continuer...", passage113_Fragment_1);
                using (styleScope("hook", "h000011301"))
                    yield return link("Cliquez pour continuer...", null, () => enchantHook("h000011301", HarloweEnchantCommand.Replace, passage113_Fragment_0));

            }
            if (Vars.crazy == 1)
            {
                yield return text("Après m\'être brièvement entretenu avec eux, j\'ai compris que sans autre statuette" +
            ", je ne parviendrais jamais à percer ce mystère. Cependant, elle a brûlé particu" +
            "lièrement longtemps quand je l\'ai jetée au feu.");
                yield return lineBreak();
                yield return lineBreak();
                yield return text("J\'ai profité de ce moment et de cette chaleur pour me remettre à mes études.");
                yield return lineBreak();
                yield return lineBreak();
                //yield return enchantIntoLink("Cliquez pour continuer...", passage113_Fragment_3);
                using (styleScope("hook", "h000011303"))
                    yield return link("Cliquez pour continuer...", null, () => enchantHook("h000011303", HarloweEnchantCommand.Replace, passage113_Fragment_2));

            }
            yield return lineBreak();
            //yield return link("Cliquez pour continuer...", "CoWEvent", null);
            yield return text(" ");
            yield return lineBreak();
        }
        yield break;
    }

