    IStoryThread passage129_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Protection militaire");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Par une fraîche matinée d'avril, nos parents étaient invités à assister à une autre réunion à l'Hôtel de ville. Sachant très bien ce qu'il en résulterait, j'ai convoqué les autres membres de ma famille et nous avons concocté un plan simple pour éviter la même erreur que par le passé. Grâce à une solution de mercure et de chloroforme, nos parents se sont retrouvés dans un état de léthargie suffisant pour qu'ils ne puissent pas y assister le jour en question.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Nous nous sommes présentés à leur place en tant que substituts et nous avons proc" +
            "édé à un vote contraire au précédent.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.barracks == "oui")
        {
            yield return text("En raison de notre décision, la ");
            using (styleScope("bold", true))
            {
                yield return text("Caserne n\'est pas construite en ville");
            }
            yield return text(". L\'escalade de la tension de la ligne temporelle d\'origine a été enrayée, ou tou" +
            "t du moins atténuée.");
        }
        if (Vars.barracks == "non")
        {
            yield return text("En raison de notre décision, la ");
            using (styleScope("bold", true))
            {
                yield return text("Caserne est construite en ville");
            }
            yield return text(". L\'escalade de la tension de la ligne temporelle d\'origine a été enrayée, ou tou" +
            "t du moins atténuée.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "SeedResolution", null);
        yield return lineBreak();
        yield break;
    }


