    IStoryThread passage132_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Thé de l\'après-midi");
        }
        yield return lineBreak();
        if (Vars.bldg1 == 0 || Vars.bldg1 == "")
        {
            Vars.teaopt = "Caserne";
        }
        else
        {
            Vars.teaopt = "Avant-poste";
        }
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Tous les joueurs peuvent de nouveau voir le livret Histoire.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"C'était absolument épouvantable. Du thé astringent provenant d'une obscure région de l'orient - des biscuits amers et rassis à la canneberge, du miel de fleurs sauvages, et de la crème bon marché - c'était sans aucun doute le pire goûter auquel j'avais eu le déplaisir de participer. Et dire que la Monarchie était responsable d'un après-midi aussi désastreux.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Mais quelle était cette aristocratie ? J\'en ai entièrement réévalué ma position. " +
            "Si l\'on pouvait me servir des digestifs indigestes alors peut-être pouvais-je m\'" +
            "assurer que la noblesse ait quelques problèmes de digestion en brûlant le lieu ");
        yield return text(Vars.teaopt);
        yield return text(" ");
        yield return text("! Cela aurait au moins le mérite de m\'éviter de m\'y rendre en cas d\'invitation.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Cependant, un plan aussi délicat que celui-ci nécessitait une machination des plu" +
            "s complexe à mettre en œuvre. C\'est donc à regret que j\'ai abandonné le sort de " +
            "cette opération aux caprices des membres de ma famille, que j\'aime tendrement.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.players == 2)
        {
            yield return link("Cliquez pour continuer...", "2PAfternoonBid", null);
        }
        else
        {
            yield return link("Cliquez pour continuer...", "AfternoonTeab", null);
        }
        yield return lineBreak();
        yield break;
    }


