    IStoryThread passage137_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Tel est notre devoir");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ah ! Qu'il est troublant d'être de noble naissance. Les habitants de la ville font des génuflexions en ma présence, les militaires sont disposés à accepter mes généreuses donations et la couronne ressent plus que jamais une certaine affinité avec ma personne, et pourtant je ressens une profonde déchirure interne. Ma loyauté va-t-elle à l'État ou à moi-même ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Malheureusement, il se pourrait que cette décision ne dépende pas que de moi. Mais si les autres membres de ma famille - que j'aime tendrement - et moi-même, pouvions combiner nos intérêts, l'aristocratie pourrait en tenir compte. La région devait-elle être dirigée par une monarchie au ");
        using (styleScope("bold", true))
        {
            yield return text("poing de fer");
        }
        yield return text(", écrasant toute opposition sans se soucier du bien-être de ses habitants ? Ou bi" +
            "en est-ce que le ralliement ");
        using (styleScope("bold", true))
        {
            yield return text("bienveillant");
        }
        yield return text(" ");
        yield return text("du peuple serait mieux à même de servir nos intérêts, même si cela peut nous valo" +
            "ir d\'attirer l\'attention de la royauté ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Il était probable que nos premières actions aient renforcé nos convictions. Dans " +
            "un cas comme dans l\'autre, il était temps de prendre une décision. Nous savions " +
            "ce qui était préférable pour ");
        yield return text(Vars.townname);
        yield return text(".");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.players == 2)
        {
            yield return link("Cliquez ici pour continuer...", "2PCoWEvent", null);
        }
        else
        {
            yield return link("Cliquez ici pour continuer...", "CoWEventb", null);
        }
        yield return lineBreak();
        yield break;
    }


