    // #140: ForewordScen2

    void passage140_Init()
    {
        this.Passages[@"ForewordScen2"] = new StoryPassage(@"ForewordScen2", new string[] { "revised", }, passage140_Main);
    }

    IStoryThread passage140_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Temps de Guerre : les souvenirs de trois générations");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"À vous qui me lisez, c'est avec une certaine émotion que je soumets à votre attention ce vaste ouvrage : un manuscrit volumineux récemment découvert – un mémoire épique rédigé sur trois générations. Il s'agit d'une œuvre aussi monumentale et déconcertante qu'elle est révolutionnaire ; un aperçu des rouages internes du véritable esprit scientifique.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Quand j'ai découvert ces feuillets immaculés, à grands frais personnels, j'ai entrepris de m'assurer que cette histoire importante soit publiée et diffusée. C'est un ouvrage qui permettra peut-être de comprendre la réputation d'excentricité de mes ancêtres.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Bien que j'admette que ma propre évaluation soit biaisée, puisque l'on y évoque ma propre lignée, je vous soumets cette prosopographie exhaustive et aussi précise que possible. Comme vous pourrez rapidement le constater, il s'agit d'une chronique d'événements résolument fantastiques, mais dont la véracité est attestée par mes propres recherches et qui constitue un des ouvrages les plus importants jamais imprimé.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Je me dois toutefois de mettre en garde les lecteurs les plus sensibles. Même si vous trouverez dans ces pages un brillant catalogue de réalisations et d'accomplissements, y sont aussi décrits les revers qu'il a fallu surmonter pour atteindre ces objectifs. Aussi macabres, sinistres et horribles soient-ils, j'ai retranscrit fidèlement le texte original sans édulcorer son contenu effroyable. Comme l'on peut s'y attendre, en révélant les composantes de base de l'univers, nous dévoilons autant de lumière que de ténèbres. Car sans les ténèbres, nous ne pouvons prendre la véritable mesure de l'éclat de la lumière.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "ATimeofWarIntro", null);
        yield return lineBreak();
        yield break;
    }


