    IStoryThread passage147_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Menace de guerre");
        }
        yield return lineBreak();
        yield return text(@"Le spectre de la guerre hantait la petite ville. La tension idéologique éclatait en démonstrations bruyantes et en rassemblements de la paysannerie près de l'hôtel de ville. Malgré cette folle agitation, je commençais à apprécier ces moments au cours desquels le calme étrange de la soirée était déchiré par des cris d'angoisse.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les Séparatistes se sentaient méprisés par le gouvernement aristocratique et voulaient faire sécession. Leurs tactiques impétueuses visaient à provoquer le soulèvement du prolétariat. Les Monarchistes Unifiés redoutaient la déstabilisation anarchique de l'économie à un moment aussi crucial de l'industrialisation. J'ai rapidement pu déterminer que ");
        using (styleScope("bold", true))
        {
            yield return text("la ville soutenait les ");
            yield return text(Vars.warwinner);
        }
        yield return text(".");
        yield return lineBreak();
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage147_Fragment_1);
        using (styleScope("hook", "h000014701"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000014701", HarloweEnchantCommand.Replace, passage147_Fragment_0));

        yield return lineBreak();
        yield break;
    }

