    // .............
    // #148: ParadoxTimeRandom

    void passage148_Init()
    {
        this.Passages[@"ParadoxTimeRandom"] = new StoryPassage(@"ParadoxTimeRandom", new string[] { "revised", }, passage148_Main);
    }

    IStoryThread passage148_Main()
    {
        if (Vars.timemistake == 1)
        {
            using (styleScope("bold", true))
            {
                yield return text("Regain de productivité");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"La machine temporelle s'est avérée inestimable pour la productivité. Alors que la populace se chamaillait et ne voyait que ses intérêts personnels, créant et détruisant la région à différents degrés d'horreur existentielle aux conséquences imprévisibles, mon couple et mes serviteurs jouissaient d'une certaine tranquillité et nous avons pu profiter de notre solitude.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"En actionnant un simple interrupteur électrique, la structure cuivrée de l'appareil me renvoyait avant une expérience ratée. J'ai rapidement pris l'habitude des visites d'autres moi-même. J'ai même partagé du thé avec plusieurs versions de ma personne et réexaminer une thèse particulièrement ardue. Bien que ce processus me faisait vieillir plus rapidement que prévu, les ingrédients que j'ai pu économiser et les conversations enrichissantes en valaient largement la peine.");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage148_Fragment_1);
            using (styleScope("hook", "h000014801"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000014801", HarloweEnchantCommand.Replace, passage148_Fragment_0));

        }
        if (Vars.timemistake == 2)
        {
            using (styleScope("bold", true))
            {
                yield return text("Un objectif clair");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Le progrès technologique issu du futur, la stabilité octroyée par le fait de savoir que l'on peut changer son passé, la possibilité de remonter dans le temps pour s'aider soi-même à surmonter une journée difficile ; l'accès généralisé à une machine temporelle pourrait permettre d'établir une utopie quasiment parfaite !");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Bien que l'absence de chaos ait été une certaine déception, les retours des élites universitaires m'ont ravi. Notre décision a eu des effets tellement bénéfiques sur le monde, que cela a fait bouillir de rage les universitaires ! Leurs sourcils froncés et leur visage d'imbéciles ridés d'inquiétude me comblaient d'une joie qui suffisait à justifier cette décision téméraire. Rapidement, cette joie a cédé la place à un objectif clair. Savoir que chacune de mes prochaines expériences provoquerait la même réaction horrifiée me comblait d'aise.");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage148_Fragment_3);
            using (styleScope("hook", "h000014803"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000014803", HarloweEnchantCommand.Replace, passage148_Fragment_2));

        }
        if (Vars.timemistake == 3)
        {
            using (styleScope("bold", true))
            {
                yield return text("Nul ne sera abandonné");
            }
            yield return lineBreak();
            yield return text(@"Si je devais oublier un instant mon humilité et décrire l'une de mes qualités les plus remarquables, je dirais que je suis une créature d'une infinie patience. Aussi, alors que les premières expériences d'altération du temps ne donnaient que des résultats insignifiants, je n'ai fait qu'observer et j'ai poursuivi mon œuvre sans trop y prêter attention. Comme tout ce qui, au début, fascine les gens, la vague d'intérêt pour la manipulation du destin a lentement cédé le pas à d'autres distractions technologiques et les machines à voyager dans le temps sont devenues de simples jouets pour enfants particulièrement populaires lors des fêtes.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Je ne parviens pas à me souvenir quand j'en ai pris conscience, peut-être cela s'est-il produit naturellement, mais alors que la ligne temporelle fluctuait lentement il semblait que les forces régissant le cosmos préféraient la stase aux caprices du chaos. Au fil des saisons, le fossé de connaissances qui me séparait des autres membres de ma famille paraissait se combler de plus en plus.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Et bien que l\'idée de l\'intervention d\'une puissance inconnue me révulsait au plu" +
            "s haut point, j\'ai tout de même apprécié que mon stoïcisme soit récompensé.");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage148_Fragment_5);
            using (styleScope("hook", "h000014805"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000014805", HarloweEnchantCommand.Replace, passage148_Fragment_4));

        }
        if (Vars.timemistake == 4)
        {
            using (styleScope("bold", true))
            {
                yield return text("Notes futures");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Lâcher dans la nature une Machine à voyager dans le temps entraîne des conséquenc" +
            "es et la dévastation est bien trop généralisée pour qu\'un seul paragraphe des mé" +
            "moires d\'un savant fou puisse en résumer la magnitude. Cependant, cela n\'a ");
            using (styleScope("bold", true))
            {
                yield return text("aucun effet sur le système de jeu");
            }
            yield return text("et sera donc ignoré. ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Il est préférable d'écrire ceci avant la sortie du jeu, Le secret de mon père, qui sera publié en 2022 et qui retrace l'histoire de ma famille. J'y ai joué quelques fois au cours de mes voyages et bien que j'eusse apprécié la présence d'une version en solitaire, il demeure de très bonne facture. ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Peut-être que l\'histoire ne correspondra plus au récit présenté dans le jeu et qu" +
            "e ce paragraphe paraîtra étrangement déplacé. Mais telle est la nature déroutant" +
            "e des voyages dans le temps.");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage148_Fragment_7);
            using (styleScope("hook", "h000014807"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000014807", HarloweEnchantCommand.Replace, passage148_Fragment_6));

        }
        if (Vars.timemistake == 5)
        {
            using (styleScope("bold", true))
            {
                yield return text("Confiance et bienveillance");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Après l'éclatant succès de l'appareil permettant d'altérer le temps, la population a désormais confiance en mon travail et me témoigne une certaine reconnaissance. Confiance et reconnaissance ? Je passe bon nombre de mes heures d'éveil à tenter d'assimiler ces concepts. Même durant les journées au cours desquelles je fais preuve de suffisamment de hardiesse pour voyager vers le passé afin de mettre un terme à cette adoration qui me retourne l'estomac, il y a toujours un quelconque larbin de la ville pour défaire ce que je fais.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Mon magnifique domaine macabre suscite désormais l'attention enthousiaste des touristes de la région. Des touristes ! Par Dieu, il va m'être presque impossible de repousser les limites de l'imagination éthique ! Je dois briser cette barrière irrationnelle d'amour et de générosité avant que cela n'entrave mon travail !");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage148_Fragment_9);
            using (styleScope("hook", "h000014809"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000014809", HarloweEnchantCommand.Replace, passage148_Fragment_8));

        }
        if (Vars.timemistake == 6)
        {
            using (styleScope("bold", true))
            {
                yield return text("Retour de la suspicion");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Comment osent-ils nous accuser de sédition ? La Machine à voyager dans le temps é" +
            "tait le don de ma famille à toute l\'humanité et pourtant ils n\'ont que les mots " +
            "imprudence et immoralité à la bouche !");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Peut-on imputer à Prométhée la responsabilité de toutes les maisons incendiées pour avoir apporté le feu aux hommes ? Le zootrope est-il responsable de tous les mauvais films tournés après son invention ? Devrions-nous bannir les parfums et l'eau de Cologne pour leur capacité à inciter les couples à plus d'intimité ? Il est tout à fait naturel que les découvertes les plus fondamentales s'accompagnent d'un minimum de potentiel insidieux.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Il est absurde de m\'attribuer un effet corrélatif et pourtant les voici de nouvea" +
            "u qui cèdent à leurs superstitions ! ");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage148_Fragment_11);
            using (styleScope("hook", "h0000148011"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h0000148011", HarloweEnchantCommand.Replace, passage148_Fragment_10));

        }
        if (Vars.timemistake == 7)
        {
            using (styleScope("bold", true))
            {
                yield return text("Une cible dans le dos");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Ils ont découvert qui l\'a fait. Le gouvernement hongrois a tout retrouvé. ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Chaque pamphlet, éditorial, journal ou plan étant signé, il était sans doute assez facile de collecter ces informations. Mais tout cela n'a servi à rien. En toute discrétion, le gouvernement hongrois a retrouvé chaque copie avec l'aide de la communauté scientifique et s'est assuré de conserver ces connaissances à son seul usage.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"La décision des membres de ma famille de disséminer ces informations a eu de terribles conséquences pour ceux qui ont choisi cette voie. Il leur était désormais inutile de terminer leur Grand Œuvre puisqu'il serait immédiatement confisqué par la police enhardie par sa capacité à accéder au flux temporel. Fort heureusement, ceux qui ont décidé de garder le silence n'ont pas pu être impliqués par simple association et sont restés libres de poursuivre leur travail.");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage148_Fragment_13);
            using (styleScope("hook", "h0000148013"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h0000148013", HarloweEnchantCommand.Replace, passage148_Fragment_12));

        }
        if (Vars.timemistake == 8)
        {
            using (styleScope("bold", true))
            {
                yield return text("Catastrophe absolue");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Chaque époque majeure de l'Histoire du monde est caractérisée par un cycle de destruction et de renouveau et cela sera probablement considéré comme un écueil mineur dans la chronologie globale des événements. Avec la facilité d'accès à un appareil capable de plier le temps et l'espace, il s'est rapidement avéré que l'individu moyen n'avait ni la maîtrise de soi, ni l'intelligence nécessaire pour éviter la destruction catastrophique de presque tous les êtres vivants d'Europe de l'est. ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Étant propriétaire d\'un domaine aux murs de pierre dominant la vallée, j\'ai pu co" +
            "nserver la plupart de mes possessions même si l\'atmosphère est désormais emprein" +
            "te d\'un soupçon de souffre et qu\'il m\'est plus difficile de me procurer des ress" +
            "ources.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Ce n\'était qu\'un revers mineur.");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage148_Fragment_15);
            using (styleScope("hook", "h0000148015"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h0000148015", HarloweEnchantCommand.Replace, passage148_Fragment_14));

        }
        yield return lineBreak();
        yield return lineBreak();
        //if (Vars.timemistake == 6)
        //{
        //    yield return link("Cliquez pour continuer...", "Paradox3b", null);
        //}
        //else if (Vars.timemistake == 8)
        //{
        //    yield return link("Cliquez pour continuer...", "Paradox3b", null);
        //}
        //else
        //{
        //    yield return link("Cliquez pour continuer...", "Paradox3", null);
        //}
        yield return lineBreak();
        yield break;
    }

