    IStoryThread passage154_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Puissance royale");
        }
        yield return lineBreak();
        yield return text("Alors que mon influence n\'était plus aussi manifeste que ");
        yield return text(macros1.either("le Lance-tigre", "la Bombe psychique", "l\'Aphrodisiaque irrésistible", "le Heaume lance-flammes"));
        yield return text(" ");
        yield return text("ou ");
        yield return text(macros1.either("la Grenade à vapeur", "la Nuée de rats pestiférés télécommandés", "la Fourche incendiaire", "l\'Armure mécanisée", "le Voleur de rêves"));
        yield return text(" ");
        yield return text(@"sur un champ de bataille dans toute leur gloire, une bourse bien remplie et un bon repas pouvaient y suppléer avec l'individu approprié. Cet individu se trouvait justement dans la propriété des Monarchistes Unifiés récemment construite en ville. Il m'arrivait de fréquenter ce bâtiment quand je voulais réorienter les politiques locales répressives de la couronne.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Application des décrets royaux");
        }
        yield return lineBreak();
        yield return text("À chaque fois que vous vous placez sur le lieu ");
        using (styleScope("bold", true))
        {
            yield return text("Conseil régional");
        }
        yield return text(" ");
        yield return text("et que vous payez 1 $, vous aurez la possibilité de promulguer un Décret royal qu" +
            "i affectera la région.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le joueur qui promulgue le ");
        using (styleScope("bold", true))
        {
            yield return text("plus de Décrets");
        }
        yield return text(" ");
        yield return text("obtiendra un bonus à la fin de la Génération.");
