    }

    IStoryThread passage170_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Famine");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"En raison de l'accroissement rapide de l'effort de guerre, il devenait de plus en plus difficile de trouver des marchandises. Quand la famine a frappé la région en 1901, des émeutes ont éclaté à cause de la pénurie alimentaire. Plusieurs idées ont été proposées pour trouver une solution - des camps de travail pour les dissidents, des établissements de rééducation, des pilules ralentissant le métabolisme - mais il ne s'agissait que de demi-mesures qui ne pouvaient en rien résoudre le problème de fond.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Même si, au début, j'ai fait cette proposition sur le ton de la plaisanterie, la méthode la plus propre, efficace et logique était d'utiliser ce que nous avions en quantité pour obtenir ce qui nous manquait. Devions-nous nous contenter de cribler de balles nos ennemis et de laisser leurs corps infester le sol ? Pourquoi devrions-nous laisser les éléments gâcher des protéines parfaitement saines ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("J\'ai décidé d\'en discuter avec les autres membres de ma famille et de procéder à " +
            "un vote.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Nous pouvions continuer de faire des promesses creuses au sujet de nouvelles sour" +
