        using (styleScope("bold", true))
        {
            yield return text("Ferme réprimande");
        }
        yield return lineBreak();
        yield return text(@"Je me rappelle la matinée au cours de laquelle la lettre m'est parvenue alors que je venais de faire ma toilette. Mes cheveux fraîchement shampouinés exhalant une odeur de romarin, je me heurtais à une sordide déception. Les mots sévères de ce membre de ma famille étaient aussi pompeux qu'une fanfare et, pourtant, il ne me lançait aucun défi et n'annonçait aucune mesure de rétorsion. L'affaire avait été réglée par des moyens détournés, et mon illustre nom au sein de la communauté scientifique, bien qu'entaché par mes actes provocateurs, n'avait eu à souffrir que du plus infime des revers.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Peut-être avais-je inconsciemment désiré l'excitation d'une escalade dans ce conflit. Ou peut-être était-ce la nature compétitive de la vraie science et de la découverte qui avait attisé en moi cette envie d'en découdre avec ma famille. Cependant, il ne servait à rien de s'attarder sur cette affaire. Le sujet était clos et j'ai de nouveau focalisé toute mon attention sur mon travail.");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage177_Fragment_1);
        using (styleScope("hook", "h000017701"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000017701", HarloweEnchantCommand.Replace, passage177_Fragment_0));

