            }
            if (Vars.dueltype == "pistolets")
            {
                yield return text(@"a titubé avant de s'effondrer sur le sol moussu. La balle avait touché une artère majeure qui ne pouvait être suturée avant une trop grande perte de sang. D'un point de vue plus pragmatique, son corps était pour le reste intact et a été ramené au domaine au cours des heures qui ont suivi.");
            }
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Alors que le sang s'écoulait en teintant de rouge le terrain de duel, j'ai voilé mes yeux avant de fuir les lieux. Le duel s'était achevé par un décès. La génération allait devoir se poursuivre en se basant uniquement sur ses instructions rédigées des semaines avant cet événement fatal.");
