            "on modifié se soit envolé dans le lointain et");
                }
                if (Vars.duelsci == "Occultisme")
                {
                    yield return text("le visage écarlate, consulter une autre page de son grimoire occulte en feignant " +
            "de manière flagrante une coupure et ");
