            }
            if (Vars.dueltype == "pistolets")
            {
                yield return text("se mettre à pleurer. Apparemment ma balle avait touché l\'épaule provoquant une dé" +
            "chirure des tissus et une blessure mineure. Incapable de supporter la douleur, j" +
            "e le voyais");
