    IStoryThread passage197_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Un héritage d\'intrigue");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Tous les joueurs peuvent de nouveau voir le livret Histoire.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Le symbole de ");
        yield return text(Vars.figure);
        yield return text(" ");
        yield return text(@"que j'exhibais en toute inconscience sur le manteau de ma cheminée était devenu un sujet de conversation en ville, l'objet central de toutes les intrigues autour de mon travail secret. Les habitants ont commencé à me poser des questions alors même que je me montrais plus audacieux et plus brusque dans mes réponses.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Cependant, j'ai rapidement découvert que les ricanements qu'il me semblait percevoir quand j'offrais quelques aperçus de mon travail secret n'étaient en rien des moqueries. Il s'agissait uniquement de quelques marques d'un dégoût approprié dû aux mesures extrêmes et nécessaires, parfois graphiques, auxquelles je devais avoir recours pour réaliser mes expériences à la pointe de l'innovation. À ma grande surprise, quand j'ai commencé à organiser une exposition choquante des œuvres préservées de ma famille, les universitaires se sont montrés enthousiastes.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Bien que je n'aie pu dissimuler dans le ton de ma voix un fort dédain pour quelques motivations extrinsèques - de pitoyables carottes agitées sous le nez de simples d'esprits - il m'est également apparu que si je pouvais les inciter à une certaine ferveur, je pouvais m'attendre à des applaudissements nourris plutôt qu'à des coups de fourche. Cela demanderait cependant de considérables efforts pour y parvenir.");
        yield return lineBreak();
        //yield return enchantIntoLink("Cliquez pour continuer...", passage197_Fragment_1);
        using (styleScope("hook", "h000019701"))
            yield return link("Cliquez pour continuer...", null, () => enchantHook("h000019701", HarloweEnchantCommand.Replace, passage197_Fragment_0));

        yield return lineBreak();
        yield break;
