    // #198: MonumentVote

    void passage198_Init()
    {
        this.Passages[@"MonumentVote"] = new StoryPassage(@"MonumentVote", new string[] { "rev2", }, passage198_Main);
    }

    IStoryThread passage198_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Machine à voyager dans le temps - Publication ?");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Bien que les idées du journal de mon parent étaient à la fois obsolètes et outrageusement rudimentaires dans certains domaines, les imbéciles de l'université nous ont harcelés pour obtenir les plans du dispositif de voyage dans le temps. Pour une découverte aussi radicale et monumentale en raison de son influence sur les différentes dimensions du monde, la maigre somme qu'ils nous proposaient pour leur confier ces plans  était insultante.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Jamais je ne les leur donnerais pour qu'ils en abusent secrètement à leur discrétion. Non ! Mais les publier afin de donner la possibilité à tous les Hongrois de réécrire l'histoire ? Voilà, me semble-t-il, le genre de chaos expérimental auquel ces prétentieux universitaires ne s'attendent certainement pas !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Mais, peut-être aussi, plutôt de manière certaine, que cela pourrait avoir des ré" +
            "percussions inimaginables.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Cependant, le problème qui se posait présentement était celui du secret. Si l\'un " +
            "d\'entre nous, moi-même ou un autre membre de ma famille, décidait de publier ces" +
            " plans, n\'importe qui pourrait y avoir accès.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Je savais que chacun d\'entre nous était appelé à prendre sa propre décision et je" +
            " priais pour que ce soit la bonne.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "MonuA", null);
        yield return lineBreak();
        yield break;
    }


