    IStoryThread passage201_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("La guerre ?");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Par considération envers les personnes qui pourraient lire ces lignes et penser y déceler une lacune dans le récit de la lignée de ma famille, je vais évoquer la période de la guerre civile qui a été abordée tant de fois au cours de la génération précédente.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Bien que les détails au sujet de ce conflit mineur soient rares, j\'ai pu détermin" +
            "er que ");
        if (Vars.warwinner == "Séparatistes")
        {
            yield return text("les ");
            yield return text(Vars.warwinner);
            yield return text("étaient parvenus à utiliser la pression populaire pour établir une représentation" +
            " républicaine après juste quelques escarmouches et rebellions mineures. Travaill" +
            "ant de concert avec une monarchie de façade, un processus démocratique avait été" +
            " instauré.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Sans intérêt et terriblement ennuyeux, je ne parvenais pas à comprendre la fascin" +
            "ation de ma famille pour ces événements. Il va sans dire que cela n\'affectait en" +
            " rien mon état actuel.");
        }
        if (Vars.warwinner == "Monarchistes Unifiés")
        {
            yield return text("les ");
            yield return text(Vars.warwinner);
            yield return text(@"étaient parvenus à étouffer les événements mineurs qui se sont produits au cours des années 1860 et 1870, en répondant favorablement à quelques revendications concernant les impôts et en reléguant cette guerre civile à quelques gros titres tapageurs et sensationnalistes de nouveaux journaux.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"En fait, il était si difficile de trouver des éléments concernant ce désaccord que je ne parvenais pas à comprendre la fascination de ma famille pour ces événements terriblement banals et ennuyeux. Il va sans dire que cela n'avait que des répercussions minimes sur mes affaires en cours..");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Cliquez pour continuer...", "WhoopsUtopian", null);
        yield return lineBreak();
        yield break;
    }


