            yield return lineBreak();
            yield return text(@"Au diable les universitaires ! Je ne redoutais pas une quelconque manipulation mineure de la quatrième dimension. Ne serait-il pas immoral de refuser à la population le droit fondamental de tout être humain de pouvoir modifier son propre destin ? J'allais révéler et diffuser les secrets de la création, quelles que soient les horreurs auxquelles je m'exposais. ");
