            yield return lineBreak();
            yield return text(@"Faire connaître au grand public les moyens de construire une machine temporelle était un choix audacieux que même le plus téméraire des polymathes n'aurait le courage d'accomplir. Ma famille laisserait une empreinte indélébile dans la ligne du temps du cosmos, quelle que soit la trajectoire anarchique sur laquelle nous nous engagions.");
        }
        else
        {
            using (styleScope("bold", true))
            {
                yield return text("Un avenir sûr");
            }
            yield return lineBreak();
            yield return text(@"Même s'il aurait été audacieux de permettre à chaque citoyen de fabriquer sa propre machine afin qu'il puisse entreprendre des voyages temporels, la perte de temps potentielle était trop importante pour être ignorée. Ayant déjà l'avenir à portée de ma main, il était inutile de surfer sur les vagues du chaos. Avec la précision d'un potier travaillant l'argile, j'allais façonner un monde parfait.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Grâce à notre décision, la ville a compris toute la magnificence de notre vision " +
