        yield return lineBreak();
        yield return lineBreak();
        yield return text("Un vote contre permet aussi de pacifier la population, mais n\'accorde aucun avant" +
            "age.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
