    // .............
    // #249: ATOW-End1

    void passage249_Init()
    {
        this.Passages[@"ATOW-End1"] = new StoryPassage(@"ATOW-End1", new string[] { }, passage249_Main);
    }

    IStoryThread passage249_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Un succès Géant");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Et c\'est ainsi que ce chapitre de cette histoire s\'est terminé. C\'est un récit qu" +
            "e vous avez sans doute lu d\'innombrables fois dans les journaux ou que vous avez" +
            " entendu avec votre famille dans le calme d\'un salon autour de votre radioscope." +
            " ");
        using (styleScope("bold", true))
        {
            yield return text("L\'ampleur");
        }
        yield return text(" ");
        yield return text("de l\'expérience de ma famille m\'impressionne moi-même quand je regarde en arrière" +
            " pour la contempler dans toute sa magnificence.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Mais bon sang, je jure sur mon nom, ");
        yield return text(Vars.winner);
        yield return text(" ");
        yield return text("quatrième du nom, que j\'utiliserai cette célébrité pour soutenir mes ambitions et" +
            " atteindre les étoiles. L\'utopie ne suffit pas ; je dois viser plus haut.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.release >= 1)
        {
            yield return text(@"Étonnamment, divulguer les plans techniques de la Machine à voyager dans le temps n'a pas eu d'énormes répercutions, ou peut-être un nombre infini de conséquences, ce qui, techniquement, revient à dire que cela n'a eu aucun effet. Et si cela a eu un effet, je n'aurais très certainement pas conscience de l'effet de cet effet puisque la ligne temporelle aurait déjà altéré mes connaissances en conséquence. Il suffit de dire qu'avec le voyage dans le temps, comme dans la vraie vie, tout et rien n'a d'importance.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Qu\'est-ce qui pourrait être plus innovant qu\'une Machine à voyager dans le temps " +
            "géante ou ");
        yield return text(macros1.either("un Char arachnide géant", "un Philtre d\'amour géant", "un Portail de téléportation géant"));
        yield return text(", vous demandez-vous ? Hé bien une version encore plus MASSIVE, bien entendu ! Un" +
            "e version d\'une taille colossale !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ce n'est pas la fin ; ce n'est que le début. Ma propre histoire reste à écrire, une histoire que je forgerai sur l'enclume de l'héritage de ceux et celles qui m'ont précédé. Je ne m'arrêterai pas tant que l'éclat de mon imagination n'aura pas éclipsé celui du soleil !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("LA FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Philippe Tessier");
        }
        yield break;
    }


    // .............
    // #250: ATOW-End2

    void passage250_Init()
    {
        this.Passages[@"ATOW-End2"] = new StoryPassage(@"ATOW-End2", new string[] { }, passage250_Main);
    }

    IStoryThread passage250_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("À la traîne");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Mes amis proches et les membres de ma famille - avec la plupart desquels j'ai rompu tout contact en raison de leurs sentiments à ce sujet - se sont montrés extrêmement réservés quant à la publication de ce livre. Ils affirment que ma fascination macabre à vouloir révéler tout ceci au monde est malsaine !");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Certains, avec dérision, ont même qualifié ce travail de pseudoscience, d'homéopathie ou même de rêve fiévreux induit par de quelconques drogues, mais je leur réponds : ""Qui êtes-vous pour critiquer la lune et les étoiles à cause de la place qu'elles occupent dans le ciel ?"" Ce travail est important ! Comment peuvent-ils ne pas le comprendre ? En fait, ces étranges expériences ne font que prouver la pertinence de la science, science bien mieux étudiée, réalisée et analysée par les experts après publication dans des revues respectées.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Car même si le monde a progressé bien plus rapidement que nos contributions scientifiques, timides et peu innovantes en comparaison, je pense que l'échec de ma famille à avoir un impact sur le monde du futur est une leçon importante. Il faut que l'on se souvienne de nos contributions, non pas pour ce qu'elles ont apporté au progrès du genre humain, mais pour avoir posé les bases d'un travail que d'autres auraient ignoré au profit d'innovations plus fiables qu'ils auraient pu affiner à la perfection.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Il se peut que le monde ait évolué suffisamment pour se passer de cette science c" +
            "onsidérée comme folle, mais je crois que c\'est cet esprit qui définira l\'héritag" +
            "e des membres de ma famille. Même si ce n\'est pas le cas de leurs réalisations.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("LA FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Philippe Tessier");
        }
        yield return lineBreak();
        yield break;
    }


    // .............
    // #251: ATOW-End3

    void passage251_Init()
    {
        this.Passages[@"ATOW-End3"] = new StoryPassage(@"ATOW-End3", new string[] { }, passage251_Main);
    }

    IStoryThread passage251_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Les replis du temps");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les lecteurs éclairés peuvent déjà avoir noté que les souvenirs de ces trois générations étaient à maints égards étonnamment vivants et détaillés. Presque comme si son auteur ne s'était pas contenté de retranscrire ces moments en se basants sur les souvenirs des autres, mais qu'il en avait été le témoin direct. Si vous ne l'avez pas remarqué, alors peut-être mon niveau littéraire n'est-il pas aussi brillant que je ne le pense.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Ne semble-t-il pas étrange qu\'un individu né à ");
        yield return text(Vars.townname);
        yield return text(", une petite ville de l\'Europe de l\'Est, puisse acquérir une telle célébrité auss" +
            "i rapidement ? Assez étonnant en effet, n\'est-ce pas ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Car voyez-vous, c\'est moi, ");
        yield return text(Vars.winner);
        yield return text(@", qui me suis appliqué à compiler, à rédiger et à éditer les illustres souvenirs de ma famille. Et il ne s'agit pas d'une œuvre basée sur des souvenirs que je n'ai pas vécus, mais bien de la retranscription d'événements réels dont j'ai été le témoin direct. Recevoir en cadeau les plans techniques d'une Machine à voyager dans le temps a certains avantages.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Je n'essaierai pas de vous persuader de l'authenticité de ce récit. Avec tous les événements merveilleux et les échecs manifestes décrits dans cette longue chronique - dont, et c'est ma conviction, aucun membre de ma famille n'aurait admis de son plein gré la véracité - je n'ai aucun doute sur le fait que cette révélation porte en elle sa propre crédibilité.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"La trame temporelle étant restaurée, je me sens le devoir de proposer ce témoignage comme testament d'une lignée qui n'a pas ménagé sa peine, une lignée à laquelle je suis redevable, et de cimenter à jamais ses accomplissements dans le firmament de l'histoire scientifique.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("LA FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Philippe Tessier");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield break;
    }


    // .............
    // #252: ATOW-End4

    void passage252_Init()
    {
        this.Passages[@"ATOW-End4"] = new StoryPassage(@"ATOW-End4", new string[] { }, passage252_Main);
    }

    IStoryThread passage252_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Une trame temporelle déchaînée");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Les mots se dispersent et se reforment au fur et à mesure que je déplace mon stylo sur la page. Comme des feuilles rouillées transformées en scarabées, elles décampent vers les marges. L'encre se regroupe sur la pointe de ma plume et rentre à l'intérieur. La ficelle reliant les pages et la colle de la reliure se défont et se reconstituent encore et encore. Tout cela voltige à travers la réalité comme avec un zoopraxiscope, la projection d'images de lignes temporelles altérées par des changements mineurs.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Je suis incapable de savoir si ce mémoire est complet. J\'ignore si quelqu\'un pour" +
            "ra lire ces mots. Les veines de mes doigts changent de couleur. Les ");
        yield return text(Vars.warwinner);
        yield return text(" ");
        yield return text("ont gagné la guerre. Je ne sais pas si j\'existe ou si je suis une simple projecti" +
            "on. La ficelle reliant les pages et la colle de la reliure ... Est-ce que je me " +
            "répète ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Pouvez-vous lire ceci ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Pouvez-vous lire ces mots ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("N\'y a-t-il aucune réponse ? Qui pourrait répondre à part moi-même ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Pouvez-vous lire ceci ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("J\'ignore si quelqu\'un pourra lire ces mots. Comme des scarabées rouillés, des feu" +
            "illes qui décampent vers les marges déliées");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Pouvez-vous page au sujet stylo déplace je comme reforme et mots dispersés le");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Pouvez-vous lire ceci ?");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("LA FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Philippe Tessier");
        }
        yield return lineBreak();
        yield break;
    }


    // .............
    // #253: ATOW-End5

    void passage253_Init()
    {
        this.Passages[@"ATOW-End5"] = new StoryPassage(@"ATOW-End5", new string[] { }, passage253_Main);
    }

    IStoryThread passage253_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Louange royale");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Après le décès de mes parents bien-aimés, qui n\'ont jamais eu l\'occasion de savoi" +
            "r ce que leur influence avait permis d\'accomplir, j\'ai été en mesure de compiler" +
            " ce mémoire qui, je n\'en ai aucun doute, sera considéré à sa juste valeur.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("La royauté s\'est montrée satisfaite des succès en partie dus aux membres de ma fa" +
            "mille. Elle a apprécié leur ténacité quand ils ont fermement ");
        if (Vars.barracks == "oui")
        {
            if (Vars.endchange == "oui")
            {
                yield return text("soutenu l\'établissement d\'une caserne et d\'un bastion dans la région.");
            }
            else
            {
                yield return text("soutenu la construction d\'une caserne pour le gouvernement royal.");
            }
        }
        else
        {
            if (Vars.endchange == "oui")
            {
                yield return text("rejeté l\'idée de construire une caserne pour les forces ennemies.");
            }
            else
            {
                yield return text("refusé l\'établissement d\'une caserne coûteuse dans une région où les opinions dom" +
            "inantes étaient si tranchées.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Ils sont restés loyaux de génération en génération et ont aidé ");
        if (Vars.endchange == "oui")
        {
            yield return text("à inspirer une rébellion couronnée de succès.");
        }
        else
        {
            yield return text("à maintenir le pouvoir sans compromission.");
        }
        yield return text(" ");
        yield return text("Et quand la situation a exigé d\'avoir recours à des tactiques persuasives, ils ");
        if (Vars.endchange == "oui")
        {
            if (Vars.wardestroy > 0)
            {
                yield return text("ont utilisé des outils de destruction pour organiser un sabotage même quand cela " +
            "nuisait aux intérêts de cette bonne ville de ");
                yield return text(Vars.townname);
                yield return text(".");
            }
            else
            {
                yield return text("ont négocié une transition pacifique sans avoir besoin de détruire une partie de " +
            "la ville.");
            }
        }
        else
        {
            yield return text("n\'ont jamais failli. Par leur loyauté absolue, ils ont habilement conservé le pou" +
            "voir au cours de toutes ces générations.");
        }
        yield return text(" ");
        if (Vars.benevolent == "bienveillant")
        {
            yield return text("Leurs suggestions ont permis d\'établir un programme positif pour le peuple du roy" +
            "aume. Bien que manifestement inhabituel, il a permis un retour apaisé au pouvoir" +
            ".");
        }
        if (Vars.benevolent == "malveillant")
        {
            yield return text("Leurs suggestions ont apporté la gloire à la couronne et à la couronne seule, mêm" +
            "e quand cela se faisait au détriment du peuple.");
        }
        yield return text(" ");
        yield return text("Trois générations de service, de dévouement d\'influence.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Vais-je continuer leur œuvre ? Je ne ressens pas encore le besoin de suivre les t" +
            "races de mes chers géniteurs. Avec mon nouveau titre de Conseiller royal ");
        yield return text(Vars.winner);
        yield return text(" ");
        yield return text("quatrième du nom, et bras droit de la couronne, j\'ai très peu de temps pour m\'ado" +
            "nner à des loisirs. Peut-être qu\'un jour je manipulerai une pipette ; il est si " +
            "difficile de prévoir l\'avenir.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("J\'ai aujourd\'hui une passion d\'un autre genre et ce chapitre au sujet de nos riva" +
            "lités est clos. Et il était temps ; c\'est l\'heure du thé.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("LA FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Philippe Tessier");
        }
        yield return lineBreak();
        yield break;
    }


    // .............
    // #254: ATOW-End6

    void passage254_Init()
    {
        this.Passages[@"ATOW-End6"] = new StoryPassage(@"ATOW-End6", new string[] { }, passage254_Main);
    }

    IStoryThread passage254_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Faire pencher la balance");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ce n'est pas le récit d'un destin icarien où l'ambition l'emporte sur la raison. Non, c'est l'histoire de l'oppression en temps de guerre et de l'aveuglement de monarques consanguins pénalisant aveuglément la recherche néotérique au lieu d'embrasser toute la gloire des expériences modernes.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ce sont les annales sur trois générations de fiers membres d'une famille hongroise à l'histoire riche qui ont été chassés de chez eux et contraints de vivre en exil. Et pour quelle raison ? Pour avoir dévoilé une vérité gênante ? Pour avoir démontré que la véritable science pouvait potentiellement changer le monde et les balayer ? Mes parents ");
        using (styleScope("bold", true))
        {
            yield return text("n\'ont pas pu échapper à l\'inquisition royale");
        }
        yield return text(" ");
        yield return text("et me voici aujourd\'hui victime expatriée, arrachée à l\'héritage qui est mien.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Oh, comme j'aimerais revoir le domaine bien entretenu de ma jeunesse avec ses murs en pierre réconfortant et son portail de fer envahi par le lierre, observer la vallée depuis la véranda nord et regarder les paysans évoluer à travers le brouillard comme des crapauds dans un marais.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Mais même si moi, ");
        yield return text(Vars.winner);
        yield return text(@", j'ai goûté à la saveur de la victoire, je ne peux l'apprécier. La guerre est terminée. Mon héritage m'a été arraché. Ayez pitié de moi car je ne sais plus quelle voie emprunter. J'espère seulement que ces quelques mots éveilleront quelque chose en vous afin que vous ne partagiez pas le même destin que moi.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("LA FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Philippe Tessier");
        }
        yield break;
    }


