    IStoryThread passage256_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Légende locale");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Je vous soumets ce post-scriptum en tant que membre de la quatrième génération à " +
            "porter le nom de ");
        yield return text(Vars.winner);
        yield return text(". Les coûts d\'impression ont déjà atteint une somme qu\'il me devient difficile de" +
            " supporter après ");
        using (styleScope("bold", true))
        {
            yield return text("l\'effondrement de l\'effort de guerre");
        }
        yield return text(" ");
        yield return text("et la politique de réparations qui en a découlée, politique imposée à cette régio" +
            "n pour limiter ses possibilités de rassembler de nouvelles troupes.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("En raison de l\'incapacité des meneurs du mouvement à ");
        using (styleScope("bold", true))
        {
            yield return text("prendre des décisions difficiles mais nécessaires");
        }
        yield return text(" ");
        yield return text("afin de poursuivre l\'effort de guerre, le conflit était perdu avant même d\'avoir " +
            "commencé. ");
        if (Vars.peacecount == 1)
        {
            if (Vars.peac == 2)
            {
                yield return text("Je ne peux qu\'espérer que les victimes de cette tragique libération de gaz biochi" +
            "mique se réconforteront avec la révélation de la véritable source de cette attaq" +
            "ue.");
            }
            else
            {
                yield return text("Bien qu\'en théorie commode, j\'admets volontiers que la transformation des soldats" +
            " ennemis en biens consommables était une pratique bien regrettable qui peut pote" +
            "ntiellement en révulser plus d\'un et leur faire rejeter cet ouvrage.");
            }
            yield return lineBreak();
            yield return lineBreak();
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"J'ai conscience de ce que ma lignée représente pour la communauté internationale et bien que je souhaite clairement prendre mes distances avec toute cette affaire, en toute conscience, je ne pouvais pas permettre que soient détruits les manuscrits que j'avais découverts. Avec la publication de cet ouvrage, j'espère montrer, sans rien cacher, que les intentions des membres de ma famille n'étaient pas forcément malveillantes et que, même aujourd'hui, la science reste fondamentale.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Je reste à jamais à votre service avec humilité et conviction.  - Dr ");
        yield return text(Vars.winner);
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("LA FIN ?");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("Traduction du scénario : Philippe Tessier");
        }
        yield break;
    }


