    void passage295_Init()
    {
        this.Passages[@"SeedResolution"] = new StoryPassage(@"SeedResolution", new string[] { "rev2", }, passage295_Main);
    }

    IStoryThread passage295_Main()
    {
        if (Vars.gunsbonus == 1)
        {
            using (styleScope("bold", true))
            {
                yield return text("Un lieu de savoir");
            }
            yield return lineBreak();
            yield return text(@"Ma présence clandestine me permettait d'observer un coin du laboratoire secret progressivement recouvert de différentes notes et pages déchirées d'anciens manuscrits. À chaque soirée qui s'écoulait, cette collection obsessionnelle de connaissances se déversait sur le sol en pierre et garnissait les murs comme dans l'atelier d'un artiste, se répandant à travers la pièce comme les feuilles brunes d'une vigne éclatante. C'était un trésor de connaissances tel que jamais je n'en avais vu au cours de mes années universitaires.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Très vite, il serait impossible pour ");
            yield return text(Vars.townname);
            yield return text("d\'ignorer le génie qui vivait à sa périphérie. La région serait réputée pour les " +
            "");
            using (styleScope("bold", true))
            {
                yield return text("connaissances");
            }
            yield return text("apportées par ma famille et je savourais cette victoire dans l\'ombre, sachant que" +
            " j\'en récolterai tous les bénéfices.");
            yield return lineBreak();
            yield return lineBreak();
            //yield return enchantIntoLink("Cliquez pour continuer...", passage295_Fragment_1);
            using (styleScope("hook", "h000029501"))
                yield return link("Cliquez pour continuer...", null, () => enchantHook("h000029501", HarloweEnchantCommand.Replace, passage295_Fragment_0));

        }
        if (Vars.gunsbonus == 2)
        {
            using (styleScope("bold", true))
            {
                yield return text("Une abondance de biens");
            }
            yield return lineBreak();
            yield return text(@"Les ingrédients étaient entassés de façon désordonnée sur le sol en pierre du laboratoire. Les terres du domaine étaient bien entretenues et accueillaient un étalage exotique de curiosités zoologiques que collectionnaient mes parents. Avec une telle richesse potentielle juste sous mes pieds, il m'était difficile de continuer à me faire passer pour un membre de la famille qui ne s'en souciait guère. C'était un panorama magnifique. ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("Très vite, il serait impossible pour ");
            yield return text(Vars.townname);
