            }
            yield return lineBreak();
            yield return text(@"Même dans leurs vieux jours, mes parents s'occupaient de leurs affaires avec une telle voracité - et une telle véracité - qu'il fallait le voir pour le croire. Même si cela peut sembler déplacé, le chatoiement des pièces n'avait que peu d'intérêt à mes yeux, mais la perspective des choses merveilleuses qu'elles me permettraient de me procurer attisait très certainement la flamme de l'ambition qui grondait en moi tandis que mes cheveux prenaient une teinte cendrée. ");
            yield return lineBreak();
